    catch (RequestFailedException exception) when (IsError(exception, 404, "ResourceGroupNotFound", log))
    {
        log.LogInformation(">>> Correctly caught expected RequestFailedException (404, ResourceGroupNotFound) in 'when' clause.");
        return false; // Resource group does not exist - Correctly handled
    }
